package com.goalmoney.personal;
import android.content.*;import android.graphics.*;import android.view.*;import java.text.*;import java.util.*;
public class GoalPieView extends View {private List<Models.Goal> goals=new ArrayList<>();private final Paint p=new Paint(Paint.ANTI_ALIAS_FLAG);public GoalPieView(Context c){super(c);}public void setGoals(List<Models.Goal> g){goals=g;invalidate();}@Override protected void onDraw(Canvas c){super.onDraw(c);long total=0;for(Models.Goal g:goals)total+=g.current;if(total==0){p.setColor(Color.rgb(123,135,157));p.setTextSize(30);p.setTextAlign(Paint.Align.CENTER);c.drawText("Chưa có dữ liệu",getWidth()/2f,getHeight()/2f,p);return;}int[] cols={Color.rgb(11,87,208),Color.rgb(19,160,111),Color.rgb(244,166,42),Color.rgb(118,86,214),Color.rgb(228,72,95)};float cx=getWidth()/2f,cy=getHeight()/2f,r=Math.min(getWidth(),getHeight())*.36f;RectF box=new RectF(cx-r,cy-r,cx+r,cy+r);float start=-90;for(int i=0;i<goals.size();i++){float sweep=goals.get(i).current*360f/total;p.setColor(cols[i%cols.length]);c.drawArc(box,start,sweep,true,p);start+=sweep;}p.setColor(Color.WHITE);c.drawCircle(cx,cy,r*.52f,p);p.setColor(Color.rgb(23,32,51));p.setTextAlign(Paint.Align.CENTER);p.setTypeface(Typeface.DEFAULT_BOLD);p.setTextSize(25);c.drawText(goals.size()+" mục tiêu",cx,cy+8,p);}}
